import React, { useEffect, useState } from 'react';
import { View, Text, FlatList, ActivityIndicator, Button, StyleSheet, Linking } from 'react-native';
import { getDeliveries, updateDeliveryStatus } from '../api/client';

const OrdersScreen: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [orders, setOrders] = useState<any[]>([]);

  const fetch = async () => {
    try {
      setLoading(true);
      const data = await getDeliveries();
      setOrders(data || []);
    } catch (err) {
      console.warn(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetch(); }, []);

  const renderItem = ({ item }: { item: any }) => (
    <View style={styles.card}>
      <Text style={styles.title}>{item.trackingNumber} - {item.receiverName}</Text>
      <Text>{item.address}</Text>
      <Text>COD: {item.codAmount}</Text>
      <View style={styles.row}>
        <Button title="Gọi" onPress={() => Linking.openURL(`tel:${item.receiverPhone}`)} />
        <Button title="Bắt đầu giao" onPress={() => handleUpdate(item.id, 'DELIVERING')} />
      </View>
    </View>
  );

  const handleUpdate = async (id: string, status: any) => {
    try {
      await updateDeliveryStatus(id, status);
      fetch();
    } catch (err: any) {
      alert(err.message || 'Cập nhật thất bại');
    }
  };

  if (loading) return <ActivityIndicator style={{ flex: 1 }} />;

  return (
    <View style={{ flex: 1, padding: 12 }}>
      <FlatList data={orders} keyExtractor={(i) => i.id} renderItem={renderItem} ItemSeparatorComponent={() => <View style={{ height: 8 }} />} />
    </View>
  );
};

const styles = StyleSheet.create({
  card: { padding: 12, borderRadius: 8, backgroundColor: '#fff', elevation: 2 },
  title: { fontWeight: '600' },
  row: { flexDirection: 'row', justifyContent: 'space-between', marginTop: 8 }
});

export default OrdersScreen;
